import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F07: 存貨週轉效率同業對比 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F07_存貨週轉效率同業對比.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F07_存貨週轉效率同業對比.md"}'),o={name:"審計報告庫/財務審計/6239_力成/20260617/F07_存貨週轉效率同業對比.md"};function l(n,a,h,s,d,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="f07-存貨週轉效率同業對比-財務審計專家報告" tabindex="-1">F07: 存貨週轉效率同業對比 - 財務審計專家報告 <a class="header-anchor" href="#f07-存貨週轉效率同業對比-財務審計專家報告" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期 (Cash Cycle) 是否處於擴張狀態？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：DIO 138天（同業最佳），前三名均值277天；DPO 159天（同業最高），現金循環僅46天，力成存貨管理效率為封測業領先者。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至2025年最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>力成DIO從2022年252天一路改善至2025年138天（-45%），絕對值及改善幅度均為同業最佳。2025年同業比較：力成138天 vs 日月光177天（+28%）、南茂219天（+59%）、頎邦283天（+105%），力成完勝。現金循環天數（CCC）：力成46天，次於日月光22天但優於南茂237天、頎邦278天。DSO 67天略優於南茂94天、頎邦70天、日月光71天。力成在存貨管理及營運資金效率上具備明確的產業領先優勢。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="同業階差審核" tabindex="-1">同業階差審核 <a class="header-anchor" href="#同業階差審核" aria-label="Permalink to &quot;同業階差審核&quot;">​</a></h3><p>2025年力成DIO 138天為封測上市同業中最低。日月光為177天（高28%），南茂219天（高59%），頎邦283天（高105%）。力成的優勢來自：(1)封測服務業屬來料加工，存貨以原料/物料為主，天然DIO低於IC設計業；(2)力成近三年主動優化供應鏈（2023年調整供應商結構），DIO從252天壓縮至138天；(3)客戶多為國際記憶體大廠（Kioxia、Micron等），拉貨節奏穩定。頎邦DIO從179天暴增至283天（+58%），反映驅動IC庫存去化週期延長，力成未受此影響。</p><h3 id="營運週期透視" tabindex="-1">營運週期透視 <a class="header-anchor" href="#營運週期透視" aria-label="Permalink to &quot;營運週期透視&quot;">​</a></h3><p>合計DSO+DIO（營運週期）：2022年297天→2023年261天→2024年192天→2025年205天。2025年較2024年略增13天，主因DSO從50天升至67天，但DIO持續改善（142→138天）部分抵銷。相較同業DSO+DIO：力成205天 vs 日月光248天、南茂313天、頎邦353天，仍為最優。日月光現金循環22天主因其DPO極長（226天），反映對供應商的極強議價力。</p><h3 id="通路博弈分析" tabindex="-1">通路博弈分析 <a class="header-anchor" href="#通路博弈分析" aria-label="Permalink to &quot;通路博弈分析&quot;">​</a></h3><p>力成存貨效率的背後：不是「供不應求」的強勢溢價，而是「營運管理能力」的體現。來料加工模式使存貨構成單純（原料58.2億+物料7.4億），存貨跌價風險天然低於擁有製成品庫存的同業。但需注意2025年存貨+20.6%對應2025H2營收擴張的補庫需求，若2026年需求放緩但備料未及時調整，DIO可能回升至150天以上。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>DPO過長壓迫供應商關係</strong>：DPO 159天雖改善現金循環但也使供應商收款週期變長。若供應鏈趨緊，可能面臨供應商要求縮短帳期的風險。</li><li><strong>DSO惡化抵消存貨優勢</strong>：DSO從50天升至67天（+34%），抵消部分DIO改善效果。力成現金循環46天優於同業但優化速度放緩。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>DIO改善為封測業最優</strong>：138天遠優於日月光（198天）、南茂（176天）、頎邦（155天），為同業第一。力成主營記憶體封測，NAND/DRAM IC具標準化，製成品存貨低，跌價風險低。</li><li><strong>現金循環46天為同業最快</strong>：雖落後日月光（22天，主因DPO差異大），但優於其他同業。2025年存貨跌價迴轉43M佐證品質無虞。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>力成存貨管理效率居封測同業頂尖地位。DIO持續改善大幅優於同業。DSO惡化需關注但不動搖存貨效率優勢。綜合判定為產業領先者（Efficiency Leader）。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (inventory_check 6239, 3711, 6147, 8150)</li><li>原始數據：FinMind TaiwanStockBalanceSheet + TaiwanStockFinancialStatements</li><li>查詢參數：stock_id=6239/3711/6147/8150, start=2022-01-01, end=2025-12-31</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const D=e(o,[["render",l]]);export{u as __pageData,D as default};
